import sys

# Read symbols
syms = []
with open('/tmp/syms.txt') as f:
    for line in f:
        parts = line.strip().split(None, 2)
        if len(parts) >= 3:
            addr = int(parts[0], 16)
            size = int(parts[1])
            name = parts[2]
            syms.append((addr, size, name))

syms.sort(key=lambda x: x[0])

def lookup(pc):
    # Find the symbol containing this PC
    # Binary search for the largest addr <= pc
    lo, hi = 0, len(syms) - 1
    result = None
    while lo <= hi:
        mid = (lo + hi) // 2
        if syms[mid][0] <= pc:
            result = mid
            lo = mid + 1
        else:
            hi = mid - 1
    if result is not None:
        addr, size, name = syms[result]
        if size > 0 and pc < addr + size:
            return f"{name}+{pc - addr}"
        elif size == 0 or pc < addr + max(size, 0x10000):
            # For zero-size symbols or if within reasonable range
            return f"{name}+{pc - addr}" if size > 0 else f"{name}+{pc - addr} (approx)"
    return None

# Offsets to symbolicate per thread
threads = {
    "Thread 7020 (main, tid:7020, name:uiTest.MauiTest)": [
        (1, 0x222098),
        (2, 0x2241ac),
        (3, 0x1abc80),
        (4, 0x16de04),
    ],
    "Thread 7046 (SGen worker)": [
        (2, 0x2f4b20),
        (3, 0x2f4c84),
    ],
    "Thread 7048 (Finalizer)": [
        (2, 0x2c1a40),
    ],
}

for thread, frames in threads.items():
    print(f"\n{thread}:")
    for frame_num, pc in frames:
        sym = lookup(pc)
        if sym:
            print(f"  #{frame_num:02d} pc {pc:#010x}  libmonosgen-2.0.so  =>  {sym}")
        else:
            print(f"  #{frame_num:02d} pc {pc:#010x}  libmonosgen-2.0.so  =>  (unknown)")
